final:
module RefModule(
    input clk,
    input reset,
    input [4:0] in,
    output reg [4:0] out);

    reg [4:0] in_last;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            out <= 5'b0;
        else begin
            in_last <= in;
            out <= out | (~in_last & in);
        end
    end
endmodule
